steps.script:
async () => {
  const src=[...document.scripts].map(s=>s.src).find(u=>u && u.indexOf('ml-custom.js')>=0);
  if(!src) return {error:'no ml-custom src'};
  const txt = await fetch(src.split('?')[0]+'?cb='+Date.now()).then(r=>r.text());
  const OLD1='forEach(function(t){t.style.setProperty("font-family","Cormorant, serif","important")';
  const NEW1='forEach(function(t){var h=t.classList.contains("ml-hero__btn");t.style.setProperty("font-family","Cormorant, serif","important")';
  const OLD2='t.style.setProperty("border-radius","4px","important"),t.style.setProperty("letter-spacing","0.06em","important"),t.style.setProperty("line-height","1.2","important"),t.style.setProperty("background-color","#000","important"),t.style.setProperty("color","#fff","important")';
  const NEW2='t.style.setProperty("border-radius",h?"6px":"4px","important"),t.style.setProperty("letter-spacing","0.06em","important"),t.style.setProperty("line-height","1.2","important"),t.style.setProperty("background-color",h?"#9e4c58":"#000","important"),t.style.setProperty("color",h?"#fbf4ef":"#fff","important")';
  const c1=txt.split(OLD1).length-1, c2=txt.split(OLD2).length-1;
  let out=txt.replace(OLD1,NEW1).replace(OLD2,NEW2);
  return {origLen:txt.length, newLen:out.length, c1:c1, c2:c2, mauveAt: out.indexOf('#9e4c58'), heroVar: out.indexOf('var h=t.classList.contains'), content: out};
}
